import { Component, Output, EventEmitter, Input } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'app-search-bar',
  standalone: true,
  imports: [CommonModule, FormsModule],
  template: `
    <div style="margin-bottom: 20px;">
      <form (ngSubmit)="handleSubmit()" style="display: flex; gap: 10px;">
        <input
          type="text"
          placeholder="Ingrese identificación del cliente"
          [(ngModel)]="identificacion"
          name="identificacion"
          [disabled]="isLoading"
          style="padding: 10px; font-size: 16px; border: 1px solid #ccc; border-radius: 4px; flex: 1;"
        />
        <button
          type="submit"
          [disabled]="isLoading"
          [style]="getButtonStyle()"
        >
          {{ isLoading ? 'Consultando...' : 'Buscar' }}
        </button>
      </form>
    </div>
  `,
})
export class SearchBarComponent {
  @Input() isLoading = false;
  @Output() search = new EventEmitter<string>();

  identificacion = '';

  handleSubmit(): void {
    if (this.identificacion.trim()) {
      this.search.emit(this.identificacion.trim());
    }
  }

  getButtonStyle(): string {
    return `
      padding: 10px 20px;
      font-size: 16px;
      background-color: ${this.isLoading ? '#ccc' : '#007bff'};
      color: white;
      border: none;
      border-radius: 4px;
      cursor: ${this.isLoading ? 'not-allowed' : 'pointer'};
    `;
  }
}
